 16→  const advanceCartStatus = useAppStore(state => state.advanceCartStatus);
 17→
 18→  const cart = useMemo(
 19→    () => appState?.vault.carts.find(entry => entry.id === route.params.cartId),
 20→    [appState, route.params.cartId]
 21→  );
 22→
 23→  if (!appState || !cart) {
 24→    return null;
 25→  }
 26→
 27→  const total = computeCartTotal(appState.vault, cart);
