  9→export function MenuScreen() {
 10→  const appState = useAppStore(state => state.appState);
 11→  const updateUserName = useAppStore(state => state.updateUserName);
 12→  const resetApp = useAppStore(state => state.resetApp);
 13→  const [userName, setUserName] = useState(appState?.user.name ?? '');
 14→
 15→  if (!appState) {
 16→    return null;
 17→  }
 18→
 19→  const completedSpend = appState.vault.carts
 20→    .filter(cart => cart.status === 'completed')
 21→    .reduce((sum, cart) => sum + cart.cartItems.reduce((itemSum, item) => itemSum + ((item.actualPrice ?? item.plannedPrice ?? 0) * item.quantity), 0), 0);
 22→
 23→  const shareSnapshot = async () => {
 24→    await Share.open({
 25→      title: 'Grock summary',
 26→      message: `Grock vault: ${appState.vault.categories.length} categories, ${appState.vault.carts.length} carts, completed spend ${formatCurrency(completedSpend)}.`,
 27→    });
 28→  };
 29→
 30→  return (
 31→    <ScrollView style={styles.screen} contentContainerStyle={styles.content}>
 32→      <Text style={styles.title}>Menu</Text>
 33→      <Text style={styles.subtitle}>Account, reset, and support surfaces for the RN migration.</Text>
 34→
 35→      <View style={styles.card}>
 36→        <Text style={styles.cardTitle}>Your name</Text>
 37→        <TextInput
 38→          style={styles.input}
 39→          value={userName}
 40→          onChangeText={setUserName}
 41→          placeholder="Your name"
 42→          placeholderTextColor={colors.mutedInk}
 43→        />
 44→        <Pressable
 45→          style={styles.primaryButton}
 46→          onPress={() => {
 47→            updateUserName(userName).catch(() => undefined);
 48→          }}
 49→        >
 50→          <Text style={styles.primaryButtonText}>Save name</Text>
 51→        </Pressable>
 52→      </View>
 53→
 54→      <View style={styles.card}>
 55→        <Text style={styles.cardTitle}>Subscription state</Text>
 56→        <Text style={styles.cardCopy}>Pro active: {appState.preferences.isPro ? 'Yes' : 'No'}</Text>
 57→        <Text style={styles.cardCopy}>
 58→          Free editable stores: {appState.preferences.freeEditableStoreKeys.length}
 59→        </Text>
 60→      </View>
 61→
 62→      <View style={styles.card}>
 63→        <Text style={styles.cardTitle}>Share summary</Text>
 64→        <Text style={styles.cardCopy}>Open the native share sheet with the current vault snapshot.</Text>
 65→        <Pressable
 66→          style={styles.primaryButton}
 67→          onPress={() => {
 68→            shareSnapshot().catch(() => undefined);
 69→          }}
 70→        >
 71→          <Text style={styles.primaryButtonText}>Share</Text>
 72→        </Pressable>
 73→      </View>
 74→
 75→      <View style={styles.card}>
 76→        <Text style={styles.cardTitle}>Danger zone</Text>
 77→        <Text style={styles.cardCopy}>Reset the RN app state back to an empty first-launch vault.</Text>
 78→        <Pressable
 79→          style={[styles.primaryButton, styles.dangerButton]}
 80→          onPress={() =>
 81→            Alert.alert('Reset Grock RN state', 'This clears the new SQLite/MMKV app state.', [
 82→              { text: 'Cancel', style: 'cancel' },
 83→              {
 84→                text: 'Reset',
 85→                style: 'destructive',
 86→                onPress: () => {
 87→                  resetApp().catch(() => undefined);
 88→                },
 89→              },
 90→            ])
