 38→      .slice()
 39→      .sort((left, right) => left.sortOrder - right.sortOrder)
 40→      .filter(category =>
 41→        !query
 42→          || category.name.toLowerCase().includes(query)
 43→          || category.items.some(item => item.name.toLowerCase().includes(query))
 44→      );
 45→  }, [appState, search]);
 46→
 47→  if (!appState) {
