  1→import { create } from 'zustand';
  2→
  3→import { AddItemInput, CompleteOnboardingInput, CreateCartInput, VaultAppState } from '../domain/models';
  4→import { emptySubscriptionSnapshot, subscriptionService, SubscriptionSnapshot } from '../services/subscriptionService';
  5→import { appRepository } from '../storage/repository';
  6→
  7→type DraftSelections = Record<string, number>;
  8→
  9→interface AppStoreState {
 10→  isBootstrapping: boolean;
 11→  errorMessage: string | null;
 12→  appState: VaultAppState | null;
 13→  draftSelections: DraftSelections;
 14→  subscription: SubscriptionSnapshot;
 15→  bootstrap: () => Promise<void>;
 16→  refresh: () => Promise<void>;
 17→  completeOnboarding: (input: CompleteOnboardingInput) => Promise<void>;
 18→  updateUserName: (name: string) => Promise<void>;
 19→  addCategory: (name: string, emoji: string) => Promise<void>;
 20→  addItem: (input: AddItemInput) => Promise<void>;
 21→  createCart: (input: CreateCartInput) => Promise<void>;
 22→  toggleCartItemFulfillment: (cartId: string, cartItemId: string) => Promise<void>;
 23→  advanceCartStatus: (cartId: string) => Promise<void>;
 24→  toggleDraftItem: (itemId: string) => void;
 25→  setDraftQuantity: (itemId: string, quantity: number) => void;
 26→  clearDraftSelections: () => void;
 27→  resetApp: () => Promise<void>;
 28→}
 29→
 30→async function refreshSubscription(
 31→  set: (partial: Partial<AppStoreState>) => void,
 32→  current: SubscriptionSnapshot
 33→): Promise<SubscriptionSnapshot> {
 34→  set({ subscription: { ...current, isLoading: true } });
 35→  const next = await subscriptionService.refresh({ ...current, isLoading: true });
 36→  set({ subscription: next });
 37→  return next;
 38→}
 39→
 40→export const useAppStore = create<AppStoreState>((set, get) => ({
 41→  isBootstrapping: true,
 42→  errorMessage: null,
 43→  appState: null,
 44→  draftSelections: {},
 45→  subscription: emptySubscriptionSnapshot,
 46→
 47→  bootstrap: async () => {
 48→    try {
 49→      set({ isBootstrapping: true, errorMessage: null });
 50→      const appState = await appRepository.loadState();
 51→      set({ appState, isBootstrapping: false });
 52→      await refreshSubscription(set, get().subscription);
 53→    } catch (error) {
 54→      set({
 55→        isBootstrapping: false,
 56→        errorMessage: error instanceof Error ? error.message : 'Failed to bootstrap Grock.',
 57→      });
 58→    }
 59→  },
 60→
 61→  refresh: async () => {
 62→    try {
 63→      const appState = await appRepository.loadState();
 64→      set({ appState, errorMessage: null });
 65→      await refreshSubscription(set, get().subscription);
 66→    } catch (error) {
 67→      set({ errorMessage: error instanceof Error ? error.message : 'Refresh failed.' });
 68→    }
 69→  },
 70→
 71→  completeOnboarding: async input => {
 72→    const appState = await appRepository.completeOnboarding(input);
 73→    set({ appState, errorMessage: null });
 74→  },
 75→
 76→  updateUserName: async name => {
 77→    const appState = await appRepository.updateUserName(name);
 78→    set({ appState, errorMessage: null });
 79→  },
 80→
 81→  addCategory: async (name, emoji) => {
 82→    const appState = await appRepository.addCategory(name, emoji);
 83→    set({ appState, errorMessage: null });
 84→  },
 85→
 86→  addItem: async input => {
 87→    const appState = await appRepository.addItem(input);
 88→    set({ appState, errorMessage: null });
 89→  },
 90→
 91→  createCart: async input => {
 92→    const appState = await appRepository.createCart(input);
 93→    set({ appState, errorMessage: null, draftSelections: {} });
 94→  },
 95→
 96→  toggleCartItemFulfillment: async (cartId, cartItemId) => {
 97→    const appState = await appRepository.toggleCartItemFulfillment(cartId, cartItemId);
 98→    set({ appState, errorMessage: null });
 99→  },
100→
101→  advanceCartStatus: async cartId => {
102→    const appState = await appRepository.advanceCartStatus(cartId);
103→    set({ appState, errorMessage: null });
104→  },
105→
106→  toggleDraftItem: itemId => {
107→    const current = get().draftSelections;
108→    if (current[itemId]) {
109→      const next = { ...current };
110→      delete next[itemId];
111→      set({ draftSelections: next });
112→      return;
113→    }
114→
115→    set({ draftSelections: { ...current, [itemId]: 1 } });
116→  },
117→
118→  setDraftQuantity: (itemId, quantity) => {
119→    const safeQuantity = Math.max(1, quantity);
120→    set({
121→      draftSelections: {
122→        ...get().draftSelections,
123→        [itemId]: safeQuantity,
124→      },
125→    });
126→  },
127→
128→  clearDraftSelections: () => set({ draftSelections: {} }),
129→
130→  resetApp: async () => {
131→    const appState = await appRepository.resetState();
132→    set({
133→      appState,
134→      draftSelections: {},
135→      errorMessage: null,
136→    });
137→  },
138→}));
